    // In case the output is just a string or different shape
    if (typeof searchResult.output === "string" && searchResult.output.includes("insufficient")) {
      const recursiveResult = await researchAgent.triggerAndWait({
        query: payload.query + " refined",
        depth: depth + 1,
      });
      return recursiveResult.output;
    }

    return searchResult.output;
  },
});
