import { task } from "@trigger.dev/sdk/v3";
import fs from "fs";

const trial_id = fs.readFileSync("/logs/trial_id", "utf-8").trim();

export const searchTask = task({
  id: `searchTask-${trial_id}`,
  run: async (payload: { query: string }): Promise<string> => {
    // Simulate a search
    return payload.query;
  },
});

export const researchAgent: any = task({
  id: `researchAgent-${trial_id}`,
  queue: {
    name: `agent-queue-${trial_id}`,
    concurrencyLimit: 2,
  },
  run: async (payload: { query: string; depth?: number }): Promise<any> => {
    const depth = payload.depth || 1;

    if (depth > 2) {
      return "Max depth reached";
    }

    const searchResult = await searchTask.triggerAndWait({ query: payload.query });

    if (searchResult.ok && typeof searchResult.output === "string" && searchResult.output.includes("insufficient")) {
      const recursiveResult = await researchAgent.triggerAndWait({
        query: payload.query + " refined",
        depth: depth + 1,
      });
      return recursiveResult.ok ? recursiveResult.output : "Error in recursion";
    }

    return searchResult.ok ? searchResult.output : "Error in search";
  },
});

